INSERT INTO public.bdd_scenarios (scenario_id, feature_area, feature_area_number, title, gherkin, status, test_type) VALUES
('LLM01-INJECT-001', 'Security', 20, 'Prompt injection detection in chat and Discord', 'Given a user sends a message with prompt injection patterns\nWhen the AI endpoint processes it\nThen injection is logged and system-role messages are stripped', 'implemented', 'unit'),
('LLM02-PII-001', 'Security', 20, 'PII redaction from AI output', 'Given AI generates a response containing email addresses or phone numbers\nWhen the output sanitizer processes it\nThen PII patterns are replaced with [REDACTED]', 'implemented', 'unit'),
('LLM05-OUTPUT-001', 'Security', 20, 'Dangerous HTML stripped from AI output', 'Given AI output contains script tags or event handlers\nWhen the sanitize stream processes it\nThen dangerous content is removed before reaching the client', 'implemented', 'unit'),
('LLM07-CANARY-001', 'Security', 20, 'System prompt canary token defense', 'Given a canary phrase is injected into the system prompt\nWhen AI output contains the canary\nThen it is redacted to prevent system prompt leakage', 'implemented', 'unit'),
('LLM10-TOKENS-001', 'Security', 20, 'Max tokens cap on AI requests', 'Given a chat or Discord AI request\nWhen the request is sent to the AI gateway\nThen max_tokens is set to prevent unbounded consumption', 'implemented', 'manual'),
('ASVS-V13-AUTH-001', 'Security', 20, 'Chat uses session JWT not static key', 'Given a user sends a chat message\nWhen the request is made to the edge function\nThen the Authorization header contains the user session JWT not the publishable key', 'implemented', 'unit'),
('LLM06-AGENCY-001', 'Security', 20, 'AI has no tool execution capability', 'Given the system prompt for Fleety\nWhen configuring the AI request\nThen no tools or function calls are provided and the prompt explicitly states no code execution', 'implemented', 'manual'),
('LLM10-INPUT-001', 'Security', 20, 'Input length limits on chat messages', 'Given a user submits a chat message\nWhen the message exceeds 4000 characters\nThen it is truncated before sending to the AI endpoint', 'implemented', 'unit');